	label: string;
	value: BooleanFilterOperator;
}> = [
	{ label: 'Is', value: 'isTrue' },
	{ label: 'Is not', value: 'isFalse' }
];

export function getDefaultOperator(variant: string): FilterOperator {
	switch (variant) {
		case 'number':
			return 'equals';
		case 'date':
			return 'equals';
		case 'select':
		case 'multi-select':
			return 'is';
		case 'checkbox':
			return 'isTrue';
		default:
			return 'contains';
	}
}

export function getOperatorsForVariant(variant: string): ReadonlyArray<{
	label: string;
	value: FilterOperator;
}> {
	switch (variant) {
		case 'number':
			return NUMBER_FILTER_OPERATORS;
		case 'date':
			return DATE_FILTER_OPERATORS;
		case 'select':
		case 'multi-select':
			return SELECT_FILTER_OPERATORS;
		case 'checkbox':
			return BOOLEAN_FILTER_OPERATORS;
		default:
			return TEXT_FILTER_OPERATORS;
	}
}

export function getFilterFn<TData>(): FilterFn<TData> {
	return (row: Row<TData>, columnId: string, filterValue: unknown): boolean => {
		if (!filterValue || typeof filterValue !== 'object') {
			return true;
		}

		const filter = filterValue as FilterValue;
		const { operator, value, endValue } = filter;

		const cellValue = row.getValue(columnId);

		if (operator === 'isEmpty') {
			return (
				cellValue === null ||
				cellValue === undefined ||
				cellValue === '' ||
				(Array.isArray(cellValue) && cellValue.length === 0)
			);
		}

		if (operator === 'isNotEmpty') {
			return !(
				cellValue === null ||
				cellValue === undefined ||
				cellValue === '' ||
				(Array.isArray(cellValue) && cellValue.length === 0)
			);
		}

		if (operator === 'isTrue') {
			return cellValue === true;
		}

		if (operator === 'isFalse') {
			return cellValue === false || !cellValue;
		}

		if (value === undefined || value === null || value === '') {
			return true;
		}

		const cellValueStr = String(cellValue ?? '').toLowerCase();
		const filterValueStr = typeof value === 'string' ? value.toLowerCase() : String(value);

		if (operator === 'contains') {
			return cellValueStr.includes(filterValueStr);
		}

		if (operator === 'notContains') {
			return !cellValueStr.includes(filterValueStr);
		}

		if (operator === 'equals') {
			if (typeof cellValue === 'number' && typeof value === 'number') {
				return cellValue === value;
			}
			if (cellValue instanceof Date && typeof value === 'string') {
				const cellDate = new Date(cellValue);
				const filterDate = new Date(value);
				return cellDate.toDateString() === filterDate.toDateString();
			}
			return cellValueStr === filterValueStr;
		}

		if (operator === 'notEquals') {
			if (typeof cellValue === 'number' && typeof value === 'number') {
				return cellValue !== value;
			}
			if (cellValue instanceof Date && typeof value === 'string') {
				const cellDate = new Date(cellValue);
				const filterDate = new Date(value);
				return cellDate.toDateString() !== filterDate.toDateString();
			}
			return cellValueStr !== filterValueStr;
		}

		if (operator === 'startsWith') {
			return cellValueStr.startsWith(filterValueStr);
		}

		if (operator === 'endsWith') {
			return cellValueStr.endsWith(filterValueStr);
		}

		if (typeof cellValue === 'number' && typeof value === 'number') {
			if (operator === 'greaterThan') {
				return cellValue > value;
			}

			if (operator === 'greaterThanOrEqual') {
				return cellValue >= value;
			}

			if (operator === 'lessThan') {
				return cellValue < value;
			}

			if (operator === 'lessThanOrEqual') {
				return cellValue <= value;
			}

			if (operator === 'isBetween' && typeof endValue === 'number') {
				return cellValue >= value && cellValue <= endValue;
			}
		}

		if (cellValue instanceof Date || typeof cellValue === 'string') {
			const cellDate = new Date(cellValue);
			if (!Number.isNaN(cellDate.getTime()) && typeof value === 'string') {
				const filterDate = new Date(value);

				if (operator === 'before') {
					return cellDate < filterDate;
				}

				if (operator === 'after') {
					return cellDate > filterDate;
				}

				if (operator === 'onOrBefore') {
					return cellDate <= filterDate;
				}

				if (operator === 'onOrAfter') {
					return cellDate >= filterDate;
				}

				if (operator === 'isBetween' && typeof endValue === 'string') {
					const filterDate2 = new Date(endValue);
					return cellDate >= filterDate && cellDate <= filterDate2;
				}
			}
		}

		if (operator === 'is') {
			if (Array.isArray(cellValue)) {
				return cellValue.some((v) => String(v) === String(value));
			}
			return String(cellValue) === String(value);
		}

		if (operator === 'isNot') {
			if (Array.isArray(cellValue)) {
				return !cellValue.some((v) => String(v) === String(value));
			}
			return String(cellValue) !== String(value);
		}

		if (operator === 'isAnyOf' && Array.isArray(value)) {
			if (Array.isArray(cellValue)) {
				return cellValue.some((v) => value.some((fv) => String(v) === String(fv)));
			}
			return value.some((fv) => String(cellValue) === String(fv));
		}

		if (operator === 'isNoneOf' && Array.isArray(value)) {
			if (Array.isArray(cellValue)) {
				return !cellValue.some((v) => value.some((fv) => String(v) === String(fv)));
			}
			return !value.some((fv) => String(cellValue) === String(fv));
		}

		return true;
	};
}

export function formatDate(
	date: Date | string | number | undefined,
	opts: Intl.DateTimeFormatOptions = {}
): string {
	if (!date) return '';

	try {
		return new Intl.DateTimeFormat('en-US', {
			month: opts.month ?? 'long',
			day: opts.day ?? 'numeric',
			year: opts.year ?? 'numeric',
			...opts
		}).format(new Date(date));
	} catch {
		return '';
	}
}

import {
	type RowData,
	type Table,
	type TableOptions,
	type TableOptionsResolved,
	type TableState,
	createTable
} from '@tanstack/table-core';
import { createSubscriber } from 'svelte/reactivity';

/**
 * Bridges TanStack Table (external reactive system) to Svelte 5.
 *
 * 1. `$effect.pre` syncs options when parent `$state` changes (not on every table read).
 * 2. `createSubscriber` on proxy reads re-runs `$derived` when the table updates.
 * 3. Wrapped change handlers are stable references so `setOptions` does not retrigger callbacks.
 *
 * @see docs/REACTIVITY.md
 */
export function createSvelteTable<TData extends RowData>(
	options: TableOptions<TData>
): Table<TData> {
	let state: Partial<TableState> = {};

	const resolvedOptions: TableOptionsResolved<TData> = mergeObjects(
		{
			state: {},
			onStateChange() {},
			renderFallbackValue: null,
			mergeOptions: (defaultOptions: TableOptions<TData>, opts: Partial<TableOptions<TData>>) => {
				return mergeObjects(defaultOptions, opts);
			}
		},
		options
	);

	const table = createTable(resolvedOptions);
	state = table.initialState;

	let notifyTableUpdate: (() => void) | null = null;
	let lastDataRef: TData[] | null = null;
	let lastColumnsRef: TableOptions<TData>['columns'] | null = null;
	let lastStateKey = '';

	const subscribe = createSubscriber((update) => {
		notifyTableUpdate = update;
		return () => {
			notifyTableUpdate = null;
		};
	});

	function wrapControlledChange<Updater>(
		handler: ((updater: Updater) => void) | undefined
	): (updater: Updater) => void {
		return (updater) => {
			handler?.(updater);
			// Notify subscribers immediately; $effect.pre syncs options before paint.
			notifyTableUpdate?.();
		};
	}

	// Stable handler refs — recreated wrappers on every setOptions caused churn/loops.
	const onColumnFiltersChange = wrapControlledChange(options.onColumnFiltersChange);
	const onSortingChange = wrapControlledChange(options.onSortingChange);
	const onPaginationChange = wrapControlledChange(options.onPaginationChange);
	const onColumnVisibilityChange = wrapControlledChange(options.onColumnVisibilityChange);
	const onRowSelectionChange = wrapControlledChange(options.onRowSelectionChange);
	const onStateChange: NonNullable<TableOptions<TData>['onStateChange']> = (updater) => {
		if (updater instanceof Function) {
			state = updater(state as TableState);
		} else {
			state = mergeObjects(state, updater);
		}

		notifyTableUpdate?.();
		options.onStateChange?.(updater);
	};

	function readReactiveData(): TData[] {
		const data = options.data as TData[] | (() => TData[]);
		return typeof data === 'function' ? data() : data;
	}

	function readReactiveState(): Partial<TableState> | undefined {
		const tableState = options.state;
		if (tableState === undefined) return undefined;
		return typeof tableState === 'function'
			? (tableState as () => Partial<TableState>)()
			: tableState;
	}

	function syncOptions() {
		table.setOptions((prev) => {
			return mergeObjects(prev, options, {
				state: mergeObjects(state, readReactiveState() ?? {}),
				onColumnFiltersChange,
				onSortingChange,
				onPaginationChange,
				onColumnVisibilityChange,
				onRowSelectionChange,
				onStateChange
			});
		});
	}

	$effect.pre(() => {
		const data = readReactiveData();
		const columns = options.columns;
		const stateKey = JSON.stringify({
			manualFiltering: options.manualFiltering,
			manualPagination: options.manualPagination,
			manualSorting: options.manualSorting,
			pageCount: options.pageCount,
			state: readReactiveState()
		});

		if (data === lastDataRef && columns === lastColumnsRef && stateKey === lastStateKey) return;
		lastDataRef = data;
		lastColumnsRef = columns;
		lastStateKey = stateKey;

		syncOptions();
		notifyTableUpdate?.();
	});

	return new Proxy(table, {
		get(target, prop, receiver) {
			subscribe();

			const value = Reflect.get(target, prop, receiver);

			if (typeof value === 'function') {
				return value.bind(target);
			}

			return value;
		}
	});
}

type MaybeThunk<T extends object> = T | (() => T | null | undefined);
type Intersection<T extends readonly unknown[]> = (T extends [infer H, ...infer R]
	? H & Intersection<R>
	: unknown) & {};

/**
 * Lazily merges several objects (or thunks) while preserving
 * getter semantics from every source.
 *
 * Proxy-based to avoid known WebKit recursion issue.
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function mergeObjects<Sources extends readonly MaybeThunk<any>[]>(
	...sources: Sources
): Intersection<{ [K in keyof Sources]: Sources[K] }> {
	const resolve = <T extends object>(src: MaybeThunk<T>): T | undefined =>
		typeof src === 'function' ? (src() ?? undefined) : src;

	const findSourceWithKey = (key: PropertyKey) => {
		for (let i = sources.length - 1; i >= 0; i--) {
			const obj = resolve(sources[i]);
			if (obj && key in obj) return obj;
		}
		return undefined;
	};

	return new Proxy(Object.create(null), {
		get(_, key) {
			const src = findSourceWithKey(key);

			return src?.[key as never];
		},

		has(_, key) {
			return !!findSourceWithKey(key);
		},

		ownKeys(): (string | symbol)[] {
			// eslint-disable-next-line svelte/prefer-svelte-reactivity
			const all = new Set<string | symbol>();
			for (const s of sources) {
				const obj = resolve(s);
				if (obj) {
					for (const k of Reflect.ownKeys(obj) as (string | symbol)[]) {
						all.add(k);
					}
				}
			}
			return [...all];
		},

		getOwnPropertyDescriptor(_, key) {
			const src = findSourceWithKey(key);
			if (!src) return undefined;
			return {
				configurable: true,
				enumerable: true,
				// eslint-disable-next-line @typescript-eslint/no-explicit-any
				value: (src as any)[key],
				writable: true
			};
		}
	}) as Intersection<{ [K in keyof Sources]: Sources[K] }>;
}

import type { Component, ComponentProps, Snippet } from "svelte";

/**
 * A helper class to make it easy to identify Svelte components in
 * `columnDef.cell` and `columnDef.header` properties.
 *
 * > NOTE: This class should only be used internally by the adapter. If you're
 * reading this and you don't know what this is for, you probably don't need it.
 *
 * @example
 * ```svelte
 * {@const result = content(context as any)}
 * {#if result instanceof RenderComponentConfig}
 *   {@const { component: Component, props } = result}
 *   <Component {...props} />
 * {/if}
 * ```
 */
export class RenderComponentConfig<TComponent extends Component> {
	component: TComponent;
	props: ComponentProps<TComponent> | Record<string, never>;
	constructor(
		component: TComponent,
		props: ComponentProps<TComponent> | Record<string, never> = {}
	) {
		this.component = component;
		this.props = props;
	}
}

/**
 * A helper class to make it easy to identify Svelte Snippets in `columnDef.cell` and `columnDef.header` properties.
 *
 * > NOTE: This class should only be used internally by the adapter. If you're
 * reading this and you don't know what this is for, you probably don't need it.
 *
 * @example
 * ```svelte
 * {@const result = content(context as any)}
 * {#if result instanceof RenderSnippetConfig}
 *   {@const { snippet, params } = result}
 *   {@render snippet(params)}
 * {/if}
 * ```
 */
export class RenderSnippetConfig<TProps> {
	snippet: Snippet<[TProps]>;
	params: TProps;
	constructor(snippet: Snippet<[TProps]>, params: TProps) {
		this.snippet = snippet;
		this.params = params;
	}
}

/**
 * A helper function to help create cells from Svelte components through ColumnDef's `cell` and `header` properties.
 *
 * This is only to be used with Svelte Components - use `renderSnippet` for Svelte Snippets.
 *
 * @param component A Svelte component
 * @param props The props to pass to `component`
 * @returns A `RenderComponentConfig` object that helps svelte-table know how to render the header/cell component.
 * @example
 * ```ts
 * // +page.svelte
 * const defaultColumns = [
 *   columnHelper.accessor('name', {
 *     header: header => renderComponent(SortHeader, { label: 'Name', header }),
 *   }),
 *   columnHelper.accessor('state', {
 *     header: header => renderComponent(SortHeader, { label: 'State', header }),
 *   }),
 * ]
 * ```
 * @see {@link https://tanstack.com/table/latest/docs/guide/column-defs}
 */
export function renderComponent<
	// eslint-disable-next-line @typescript-eslint/no-explicit-any
	T extends Component<any>,
	Props extends ComponentProps<T>,
>(component: T, props: Props = {} as Props) {
	return new RenderComponentConfig(component, props);
}

/**
 * A helper function to help create cells from Svelte Snippets through ColumnDef's `cell` and `header` properties.
 *
 * The snippet must only take one parameter.
 *
 * This is only to be used with Snippets - use `renderComponent` for Svelte Components.
 *
 * @param snippet
 * @param params
 * @returns - A `RenderSnippetConfig` object that helps svelte-table know how to render the header/cell snippet.
 * @example
 * ```ts
 * // +page.svelte
 * const defaultColumns = [
 *   columnHelper.accessor('name', {
 *     cell: cell => renderSnippet(nameSnippet, { name: cell.row.name }),
 *   }),
 *   columnHelper.accessor('state', {
 *     cell: cell => renderSnippet(stateSnippet, { state: cell.row.state }),
 *   }),
 * ]
 * ```
 * @see {@link https://tanstack.com/table/latest/docs/guide/column-defs}
 */
export function renderSnippet<TProps>(snippet: Snippet<[TProps]>, params: TProps = {} as TProps) {
	return new RenderSnippetConfig(snippet, params);
}

